async fn execute_catalogs(
    command: catalogs::CatalogsCommands,
) -> Result<serde_json::Value, Box<dyn std::error::Error>> {
    let config = Config::load();
    let base_url = format!("{}/api/catalogs", config.base_url());
    let client = ApiClient::with_base_url(&config, &base_url)?;
    let api = catalogs::CatalogsClient::new(&client);

    match command {
        catalogs::CatalogsCommands::CreateCatalogPost(args) => {
            let json = args.json.map(|s| serde_json::from_str(&s)).transpose()?;
            Ok(api.create_catalog_post(json).await?)
        }
        catalogs::CatalogsCommands::GetCatalogByCidCidIdGet(args) => {
            Ok(api.get_catalog_by_cid_cid_id_get(args.id).await?)
        }
        catalogs::CatalogsCommands::PatchCatalogMetadataCidIdMetadataPatch(args) => {
            let json = args.json.map(|s| serde_json::from_str(&s)).transpose()?;
            Ok(api.patch_catalog_metadata_cid_id_metadata_patch(args.id, json).await?)
        }
        catalogs::CatalogsCommands::GetExampleCatalogsExamplesGet(_) => Ok(api.get_example_catalogs_examples_get().await?),
        catalogs::CatalogsCommands::HealthCheckHealthzGet(_) => Ok(api.health_check_healthz_get().await?),
    }
}

